/**
 * Web Worker管理器
 * @module performance/worker/web-worker-manager
 */

import type { WebWorkerManager, WorkerTask } from '../types'
import { WorkerCommunication } from './worker-communication'
import { getConfig } from '../config'

/**
 * Web Worker管理器实现
 * 管理Worker生命周期,提供降级方案
 */
export class WebWorkerManagerImpl implements WebWorkerManager {
  private worker: Worker | null = null
  private communication: WorkerCommunication
  private workerPath: string = ''
  private supported: boolean = false

  constructor() {
    this.communication = new WorkerCommunication()
    this.checkSupport()
  }

  /**
   * 检测Worker支持
   */
  private checkSupport(): void {
    this.supported = typeof Worker !== 'undefined'
  }

  /**
   * 检测Worker支持
   */
  isSupported(): boolean {
    return this.supported
  }

  /**
   * 初始化Worker
   * @param workerPath Worker脚本路径
   */
  init(workerPath: string): void {
    const config = getConfig()

    // 检查是否启用Worker
    if (!config.worker.enabled) {
      console.debug('Worker is disabled by config')
      return
    }

    // 检查浏览器支持
    if (!this.supported) {
      console.warn('Web Worker is not supported in this environment')
      return
    }

    // 清理旧Worker
    this.terminate()

    // 创建新Worker
    try {
      this.workerPath = workerPath
      this.worker = new Worker(workerPath, { type: 'module' })
      this.communication.setWorker(this.worker)
      console.debug('Worker initialized:', workerPath)
    } catch (error) {
      console.error('Failed to initialize Worker:', error)
      this.worker = null
    }
  }

  /**
   * 发送消息
   * @param task 任务
   * @returns Promise结果
   */
  async postMessage<T = any, R = any>(task: Omit<WorkerTask<T>, 'id'>): Promise<R> {
    const config = getConfig()

    // 如果Worker未启用或不支持,使用降级方案
    if (!config.worker.enabled || !this.supported || !this.worker) {
      return this.fallback<T, R>(task)
    }

    // 使用Worker执行
    return this.communication.postMessage<T, R>(task)
  }

  /**
   * 降级方案:在主线程执行
   * @param task 任务
   * @returns 结果
   */
  private async fallback<T = any, R = any>(task: Omit<WorkerTask<T>, 'id'>): Promise<R> {
    console.debug('Using fallback for task:', task.type)

    // 根据任务类型执行相应操作
    switch (task.type) {
      case 'translate':
        // 这里应该调用主线程的翻译函数
        // 由于我们不知道具体的翻译实现,这里返回模拟结果
        return `[Fallback Translated: ${(task.data as any).text}]` as R

      case 'batch-translate':
        // 批量翻译降级
        const items = (task.data as any).items as Array<{ text: string }>
        return Promise.all(
          items.map(item => Promise.resolve(`[Fallback Translated: ${item.text}]`))
        ) as Promise<R>

      default:
        throw new Error(`Unknown task type: ${task.type}`)
    }
  }

  /**
   * 终止Worker
   */
  terminate(): void {
    if (this.worker) {
      this.worker.terminate()
      this.worker = null
      this.communication.clearPending()
      console.debug('Worker terminated')
    }
  }

  /**
   * 重启Worker
   */
  restart(): void {
    if (this.workerPath) {
      this.init(this.workerPath)
    }
  }

  /**
   * 获取Worker状态
   */
  getStatus(): {
    supported: boolean
    initialized: boolean
    pendingCount: number
  } {
    return {
      supported: this.supported,
      initialized: this.worker !== null,
      pendingCount: this.communication.getPendingCount()
    }
  }
}

/**
 * 全局Worker管理器实例
 */
export const webWorkerManager = new WebWorkerManagerImpl()
