/**
 * 缓存管理器
 * @module performance/cache/cache-manager
 */

import type { CacheManager, CacheType, LRUCache, CacheStats } from '../types'
import { LRUCacheImpl } from './lru-cache'
import { getConfig } from '../config'

/**
 * 缓存管理器实现
 * 统一管理多种类型的缓存
 */
export class CacheManagerImpl implements CacheManager {
  private caches: Map<CacheType, LRUCache<any, any>>

  constructor() {
    this.caches = new Map()
    this.initCaches()
  }

  /**
   * 初始化各种缓存实例
   */
  private initCaches(): void {
    const config = getConfig()

    // 创建样式缓存
    this.caches.set(
      'style',
      new LRUCacheImpl<string, any>(config.cache.styleMaxSize)
    )

    // 创建翻译缓存
    this.caches.set(
      'translation',
      new LRUCacheImpl<string, string>(config.cache.translationMaxSize)
    )

    // 创建自动补全缓存
    this.caches.set(
      'autocomplete',
      new LRUCacheImpl<string, any[]>(config.cache.autocompleteMaxSize)
    )
  }

  /**
   * 获取指定类型的缓存实例
   * @param type 缓存类型
   * @returns LRU缓存实例
   */
  getCache<K = string, V = any>(type: CacheType): LRUCache<K, V> {
    let cache = this.caches.get(type)

    if (!cache) {
      // 如果缓存不存在,创建默认大小的缓存
      cache = new LRUCacheImpl<K, V>(50)
      this.caches.set(type, cache)
    }

    return cache as LRUCache<K, V>
  }

  /**
   * 清除所有缓存
   */
  clearAll(): void {
    this.caches.forEach((cache) => {
      cache.clear()
    })
  }

  /**
   * 清除指定类型的缓存
   * @param type 缓存类型
   */
  clearCache(type: CacheType): void {
    const cache = this.caches.get(type)
    if (cache) {
      cache.clear()
    }
  }

  /**
   * 获取所有缓存的统计信息
   * @returns 缓存统计映射
   */
  getAllStats(): Record<CacheType, CacheStats> {
    const stats: Partial<Record<CacheType, CacheStats>> = {}

    this.caches.forEach((cache, type) => {
      stats[type] = cache.getStats()
    })

    return stats as Record<CacheType, CacheStats>
  }

  /**
   * 获取指定类型缓存的统计信息
   * @param type 缓存类型
   * @returns 缓存统计
   */
  getStats(type: CacheType): CacheStats | undefined {
    const cache = this.caches.get(type)
    return cache?.getStats()
  }

  /**
   * 重新初始化缓存
   * 用于配置更新后重新创建缓存
   */
  reinit(): void {
    this.clearAll()
    this.caches.clear()
    this.initCaches()
  }
}

/**
 * 全局缓存管理器实例
 */
export const cacheManager = new CacheManagerImpl()
