/**
 * 动态防抖函数
 * @module performance/debounce/dynamic-debounce
 */

import type { DebouncedFunction, DynamicDebounceOptions } from '../types'
import { inputTracker } from './input-tracker'
import { getConfig } from '../config'

/**
 * 创建动态防抖函数
 * @param fn 要防抖的函数
 * @param options 防抖选项
 * @returns 防抖后的函数
 */
export function createDynamicDebounce<T extends (...args: any[]) => any>(
  fn: T,
  options?: DynamicDebounceOptions
): DebouncedFunction<T> {
  const config = getConfig()

  // 合并选项
  const {
    minDelay = config.debounce.minDelay,
    maxDelay = config.debounce.maxDelay,
    adaptive = config.debounce.adaptive,
    immediate = false
  } = options || {}

  let timeoutId: ReturnType<typeof setTimeout> | null = null
  let lastArgs: Parameters<T> | null = null
  let lastThis: any = null

  /**
   * 获取当前延迟时间
   */
  const getDelay = (): number => {
    if (adaptive) {
      return inputTracker.getRecommendedDelay()
    }
    return minDelay
  }

  /**
   * 执行函数
   */
  const execute = () => {
    if (lastArgs !== null) {
      fn.apply(lastThis, lastArgs)
      lastArgs = null
      lastThis = null
    }
  }

  /**
   * 防抖函数
   */
  const debounced = function (this: any, ...args: Parameters<T>) {
    // 记录输入事件
    if (adaptive) {
      inputTracker.recordInput()
    }

    // 保存参数和上下文
    lastArgs = args
    lastThis = this

    // 清除之前的定时器
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
    }

    // 立即执行模式
    if (immediate && timeoutId === null) {
      execute()
      timeoutId = setTimeout(() => {
        timeoutId = null
      }, getDelay())
      return
    }

    // 设置新的定时器
    timeoutId = setTimeout(() => {
      execute()
      timeoutId = null
    }, getDelay())
  } as DebouncedFunction<T>

  /**
   * 取消待执行的防抖
   */
  debounced.cancel = () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
      timeoutId = null
      lastArgs = null
      lastThis = null
    }
  }

  /**
   * 立即执行待执行的防抖
   */
  debounced.flush = () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
      execute()
      timeoutId = null
    }
  }

  return debounced
}

/**
 * 创建简单防抖函数(非动态)
 * @param fn 要防抖的函数
 * @param delay 延迟时间
 * @returns 防抖后的函数
 */
export function createDebounce<T extends (...args: any[]) => any>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  return createDynamicDebounce(fn, {
    minDelay: delay,
    maxDelay: delay,
    adaptive: false
  })
}

/**
 * 创建节流函数
 * @param fn 要节流的函数
 * @param interval 节流间隔
 * @returns 节流后的函数
 */
export function createThrottle<T extends (...args: any[]) => any>(
  fn: T,
  interval: number
): DebouncedFunction<T> {
  let lastTime = 0
  let timeoutId: ReturnType<typeof setTimeout> | null = null
  let lastArgs: Parameters<T> | null = null
  let lastThis: any = null

  const execute = () => {
    if (lastArgs !== null) {
      fn.apply(lastThis, lastArgs)
      lastArgs = null
      lastThis = null
    }
  }

  const throttled = function (this: any, ...args: Parameters<T>) {
    const now = Date.now()
    lastArgs = args
    lastThis = this

    if (now - lastTime >= interval) {
      // 超过间隔,立即执行
      execute()
      lastTime = now
    } else {
      // 未超过间隔,设置定时器在剩余时间后执行
      if (timeoutId !== null) {
        clearTimeout(timeoutId)
      }
      timeoutId = setTimeout(() => {
        execute()
        lastTime = Date.now()
        timeoutId = null
      }, interval - (now - lastTime))
    }
  } as DebouncedFunction<T>

  throttled.cancel = () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
      timeoutId = null
      lastArgs = null
      lastThis = null
    }
  }

  throttled.flush = () => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId)
      execute()
      lastTime = Date.now()
      timeoutId = null
    }
  }

  return throttled
}
