/**
 * 防抖控制器
 * @module performance/debounce/debounce-controller
 */

import type { DebounceController, DebouncedFunction, DynamicDebounceOptions } from '../types'
import { createDynamicDebounce } from './dynamic-debounce'
import { inputTracker } from './input-tracker'

// 重新导出 createDynamicDebounce 以便外部使用
export { createDynamicDebounce }

/**
 * 防抖控制器实现
 * 整合输入追踪和动态防抖,提供统一的管理接口
 */
export class DebounceControllerImpl implements DebounceController {
  /** 防抖函数映射 */
  private debouncedFunctions: Map<string, DebouncedFunction<any>> = new Map()

  /**
   * 创建动态防抖函数
   * @param fn 要防抖的函数
   * @param options 防抖选项
   * @returns 防抖后的函数
   */
  createDynamicDebounce<T extends (...args: any[]) => any>(
    fn: T,
    options?: DynamicDebounceOptions
  ): DebouncedFunction<T> {
    return createDynamicDebounce(fn, options)
  }

  /**
   * 注册防抖函数
   * @param id 函数标识
   * @param fn 要防抖的函数
   * @param options 防抖选项
   * @returns 防抖后的函数
   */
  register<T extends (...args: any[]) => any>(
    id: string,
    fn: T,
    options?: DynamicDebounceOptions
  ): DebouncedFunction<T> {
    const debounced = this.createDynamicDebounce(fn, options)
    this.debouncedFunctions.set(id, debounced)
    return debounced
  }

  /**
   * 获取已注册的防抖函数
   * @param id 函数标识
   * @returns 防抖函数或undefined
   */
  get<T extends (...args: any[]) => any>(id: string): DebouncedFunction<T> | undefined {
    return this.debouncedFunctions.get(id) as DebouncedFunction<T> | undefined
  }

  /**
   * 取消指定防抖函数
   * @param id 函数标识
   */
  cancel(id: string): void {
    const debounced = this.debouncedFunctions.get(id)
    if (debounced) {
      debounced.cancel()
    }
  }

  /**
   * 立即执行指定防抖函数
   * @param id 函数标识
   */
  flush(id: string): void {
    const debounced = this.debouncedFunctions.get(id)
    if (debounced) {
      debounced.flush()
    }
  }

  /**
   * 取消所有防抖函数
   */
  cancelAll(): void {
    this.debouncedFunctions.forEach((debounced) => {
      debounced.cancel()
    })
  }

  /**
   * 更新防抖时间
   * 注意:此方法仅影响新创建的防抖函数
   * 已创建的防抖函数会根据输入速度自动调整
   * @param delay 延迟时间(未使用,保留接口兼容性)
   */
  updateDelay(delay: number): void {
    // 动态防抖会根据输入速度自动调整
    // 此方法保留用于接口兼容性
    console.debug('Dynamic debounce adjusts delay automatically based on input speed')
  }

  /**
   * 记录输入事件
   */
  recordInput(): void {
    inputTracker.recordInput()
  }

  /**
   * 清除所有防抖函数
   */
  clear(): void {
    this.cancelAll()
    this.debouncedFunctions.clear()
  }
}

/**
 * 全局防抖控制器实例
 */
export const debounceController = new DebounceControllerImpl()
