/**
 * Watch管理器
 * @module performance/watch/watch-manager
 */

import { watch, triggerRef, type Ref, type WatchSource } from 'vue'
import type { WatchManager, WatchCallback, WatchStopHandle, WatcherConfig } from '../types'
import { getConfig } from '../config'

/**
 * Watcher信息
 */
interface WatcherInfo {
  /** 停止句柄 */
  stop: WatchStopHandle
  /** 配置 */
  config: WatcherConfig
  /** 触发次数 */
  triggerCount: number
}

/**
 * Watch管理器实现
 * 优化Vue组件的watch监听机制,减少深度watch的使用
 */
export class WatchManagerImpl implements WatchManager {
  /** 监听器映射 */
  private watchers: Map<string, WatcherInfo> = new Map()
  /** 触发次数统计 */
  private triggerCount: number = 0

  /**
   * 注册浅层watch
   * @param source 监听源
   * @param callback 回调函数
   * @param config 配置
   * @returns 停止句柄
   */
  registerShallowWatch<T>(
    source: WatchSource<T>,
    callback: WatchCallback<T>,
    config?: WatcherConfig
  ): WatchStopHandle {
    const finalConfig = {
      deep: false,
      immediate: config?.immediate ?? false,
      ...config
    }

    const stop = watch(
      source,
      (newValue, oldValue) => {
        this.triggerCount++
        const watcherId = this.findWatcherId(source)
        if (watcherId) {
          const info = this.watchers.get(watcherId)
          if (info) {
            info.triggerCount++
          }
        }
        callback(newValue, oldValue)
      },
      {
        deep: finalConfig.deep,
        immediate: finalConfig.immediate
      }
    )

    return stop
  }

  /**
   * 注册watch(根据配置决定是否使用浅层)
   * @param id 监听器标识
   * @param source 监听源
   * @param callback 回调函数
   * @param config 配置
   * @returns 停止句柄
   */
  register<T>(
    id: string,
    source: WatchSource<T>,
    callback: WatchCallback<T>,
    config?: WatcherConfig
  ): WatchStopHandle {
    const performanceConfig = getConfig()
    const finalConfig = {
      deep: config?.deep ?? !performanceConfig.watch.shallow,
      shallow: config?.shallow ?? performanceConfig.watch.shallow,
      immediate: config?.immediate ?? false,
      name: config?.name ?? id
    }

    const stop = watch(
      source,
      (newValue, oldValue) => {
        this.triggerCount++
        const info = this.watchers.get(id)
        if (info) {
          info.triggerCount++
        }
        callback(newValue, oldValue)
      },
      {
        deep: !finalConfig.shallow,
        immediate: finalConfig.immediate
      }
    )

    // 保存监听器信息
    this.watchers.set(id, {
      stop,
      config: finalConfig,
      triggerCount: 0
    })

    return stop
  }

  /**
   * 手动触发更新
   * @param ref 要触发的ref
   */
  triggerUpdate(ref?: Ref<any>): void {
    if (ref) {
      triggerRef(ref)
    }
    this.triggerCount++
  }

  /**
   * 批量注册监听器
   * @param watchers 监听器数组
   * @returns 停止句柄数组
   */
  registerBatch(
    watchers: Array<{
      source: WatchSource<any>
      callback: WatchCallback
      config?: WatcherConfig
    }>
  ): WatchStopHandle[] {
    return watchers.map((watcher, index) => {
      return this.registerShallowWatch(watcher.source, watcher.callback, watcher.config)
    })
  }

  /**
   * 取消指定监听器
   * @param id 监听器标识
   */
  cancel(id: string): void {
    const info = this.watchers.get(id)
    if (info) {
      info.stop()
      this.watchers.delete(id)
    }
  }

  /**
   * 清理所有监听器
   */
  cleanup(): void {
    this.watchers.forEach((info) => {
      info.stop()
    })
    this.watchers.clear()
  }

  /**
   * 获取监听器统计信息
   * @param id 监听器标识
   * @returns 触发次数
   */
  getTriggerCount(id?: string): number {
    if (id) {
      const info = this.watchers.get(id)
      return info?.triggerCount ?? 0
    }
    return this.triggerCount
  }

  /**
   * 获取所有监听器信息
   */
  getAllWatchers(): Map<string, WatcherInfo> {
    return new Map(this.watchers)
  }

  /**
   * 查找监听器ID
   * @param source 监听源
   * @returns 监听器ID或undefined
   */
  private findWatcherId(source: WatchSource<any>): string | undefined {
    for (const [id, info] of this.watchers.entries()) {
      // 简单比较,实际应用中可能需要更复杂的比较逻辑
      if (info.config.name === source) {
        return id
      }
    }
    return undefined
  }
}

/**
 * 全局Watch管理器实例
 */
export const watchManager = new WatchManagerImpl()
