/**
 * 虚拟滚动器
 * @module performance/virtual-scroll/virtual-scroller
 */

import type { VirtualScroller, VirtualScrollerConfig, VisibleRange, ListItem } from '../types'
import { getConfig } from '../config'

/**
 * 虚拟滚动器实现
 * 优化大规模列表的渲染性能
 */
export class VirtualScrollerImpl implements VirtualScroller {
  private config: VirtualScrollerConfig
  private items: ListItem[] = []
  private enabled: boolean = false

  constructor() {
    const defaultConfig = getConfig()
    this.config = {
      itemHeight: 40,
      bufferSize: defaultConfig.virtualScroll.bufferSize,
      threshold: defaultConfig.virtualScroll.threshold,
      containerHeight: 600
    }
  }

  /**
   * 初始化
   * @param config 配置
   */
  init(config: VirtualScrollerConfig): void {
    this.config = { ...this.config, ...config }
  }

  /**
   * 更新列表数据
   * @param items 列表项
   */
  updateItems(items: ListItem[]): void {
    this.items = items
    this.updateEnabled()
  }

  /**
   * 更新启用状态
   */
  private updateEnabled(): void {
    const config = getConfig()
    if (!config.virtualScroll.enabled) {
      this.enabled = false
      return
    }
    this.enabled = this.items.length > (this.config.threshold ?? 50)
  }

  /**
   * 是否启用虚拟滚动
   */
  isEnabled(): boolean {
    return this.enabled
  }

  /**
   * 计算可视范围
   * @param scrollTop 滚动位置
   * @returns 可视范围
   */
  calculateVisibleRange(scrollTop: number): VisibleRange {
    const { itemHeight, bufferSize = 5, containerHeight = 600 } = this.config
    const itemCount = this.items.length

    // 边界处理
    if (itemCount === 0) {
      return {
        start: 0,
        end: 0,
        paddingTop: 0,
        paddingBottom: 0
      }
    }

    // 修正scrollTop
    const normalizedScrollTop = Math.max(0, scrollTop)

    // 计算可视数量
    const visibleCount = Math.ceil(containerHeight / itemHeight)

    // 计算起始索引
    const startIndex = Math.max(0, Math.floor(normalizedScrollTop / itemHeight) - bufferSize)

    // 计算结束索引
    const endIndex = Math.min(
      itemCount - 1,
      startIndex + visibleCount + 2 * bufferSize
    )

    // 计算padding
    const paddingTop = startIndex * itemHeight
    const paddingBottom = (itemCount - endIndex - 1) * itemHeight

    return {
      start: startIndex,
      end: endIndex,
      paddingTop,
      paddingBottom
    }
  }

  /**
   * 获取可视项
   * @param scrollTop 滚动位置
   * @returns 可视列表项
   */
  getVisibleItems(scrollTop: number): ListItem[] {
    // 如果未启用虚拟滚动,返回所有项
    if (!this.enabled) {
      return this.items
    }

    const range = this.calculateVisibleRange(scrollTop)
    return this.items.slice(range.start, range.end + 1)
  }

  /**
   * 滚动到指定索引
   * @param index 目标索引
   * @returns 滚动位置
   */
  scrollToIndex(index: number): number {
    const { itemHeight } = this.config
    const itemCount = this.items.length

    // 边界处理
    const normalizedIndex = Math.max(0, Math.min(index, itemCount - 1))

    // 计算滚动位置(将目标项滚动到可视区域中央)
    const scrollTop = normalizedIndex * itemHeight

    return scrollTop
  }

  /**
   * 获取总高度
   */
  getTotalHeight(): number {
    return this.items.length * this.config.itemHeight
  }

  /**
   * 获取项数量
   */
  getItemCount(): number {
    return this.items.length
  }

  /**
   * 更新容器高度
   * @param height 容器高度
   */
  updateContainerHeight(height: number): void {
    this.config.containerHeight = height
  }
}

/**
 * 计算可视范围(独立函数)
 * @param scrollTop 滚动位置
 * @param containerHeight 容器高度
 * @param itemHeight 项高度
 * @param itemCount 项数量
 * @param bufferSize 缓冲区大小
 * @returns 可视范围
 */
export function calculateVisibleRange(
  scrollTop: number,
  containerHeight: number,
  itemHeight: number,
  itemCount: number,
  bufferSize: number
): VisibleRange {
  // 边界处理
  if (itemCount === 0) {
    return {
      start: 0,
      end: 0,
      paddingTop: 0,
      paddingBottom: 0
    }
  }

  // 修正scrollTop
  const normalizedScrollTop = Math.max(0, scrollTop)

  // 计算可视数量
  const visibleCount = Math.ceil(containerHeight / itemHeight)

  // 计算起始索引
  const startIndex = Math.max(0, Math.floor(normalizedScrollTop / itemHeight) - bufferSize)

  // 计算结束索引
  const endIndex = Math.min(
    itemCount - 1,
    startIndex + visibleCount + 2 * bufferSize
  )

  // 计算padding
  const paddingTop = startIndex * itemHeight
  const paddingBottom = (itemCount - endIndex - 1) * itemHeight

  return {
    start: startIndex,
    end: endIndex,
    paddingTop,
    paddingBottom
  }
}
