<template>
  <div ref="containerRef" class="virtual-scroll-container" @scroll="handleScroll">
    <div
      class="virtual-scroll-content"
      :style="{
        paddingTop: `${visibleRange.paddingTop}px`,
        paddingBottom: `${visibleRange.paddingBottom}px`
      }"
    >
      <div
        v-for="(item, index) in visibleItems"
        :key="item.id || getItemKey(item, index)"
        class="virtual-scroll-item"
        :style="{ height: `${itemHeight}px` }"
      >
        <slot :item="item" :index="getRealIndex(index)"></slot>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
  import { ref, computed, watch, onMounted, onBeforeUnmount } from 'vue'
  import { VirtualScrollerImpl } from './virtual-scroller'
  import { getConfig } from '../config'

  /**
   * Props定义
   */
  interface Props {
    /** 列表数据 */
    items: ListItem[]
    /** 每项高度 */
    itemHeight?: number
    /** 缓冲区大小 */
    bufferSize?: number
    /** 启用阈值 */
    threshold?: number
    /** 生成key的函数 */
    keyGenerator?: (item: ListItem, index: number) => string | number
  }

  const props = withDefaults(defineProps<Props>(), {
    itemHeight: 40,
    bufferSize: 5,
    threshold: 50
  })

  /**
   * Emits定义
   */
  const emit = defineEmits<{
    (e: 'scroll', scrollTop: number): void
  }>()

  // 容器引用
  const containerRef = ref<HTMLElement>()

  // 虚拟滚动器实例
  const scroller = new VirtualScrollerImpl()

  // 滚动位置
  const scrollTop = ref(0)

  // 容器高度
  const containerHeight = ref(600)

  // 可视范围
  const visibleRange = ref<VisibleRange>({
    start: 0,
    end: 0,
    paddingTop: 0,
    paddingBottom: 0
  })

  // 是否启用虚拟滚动
  const enabled = computed(() => {
    const config = getConfig()
    if (!config.virtualScroll.enabled) {
      return false
    }
    return props.items.length > props.threshold
  })

  // 可视项
  const visibleItems = computed(() => {
    if (!enabled.value) {
      return props.items
    }
    return props.items.slice(visibleRange.value.start, visibleRange.value.end + 1)
  })

  /**
   * 处理滚动事件
   */
  const handleScroll = (event: Event) => {
    const target = event.target as HTMLElement
    scrollTop.value = target.scrollTop
    emit('scroll', scrollTop.value)
  }

  /**
   * 获取真实索引
   */
  const getRealIndex = (visibleIndex: number): number => {
    if (!enabled.value) {
      return visibleIndex
    }
    return visibleRange.value.start + visibleIndex
  }

  /**
   * 获取项key
   */
  const getItemKey = (item: ListItem, index: number): string | number => {
    if (props.keyGenerator) {
      return props.keyGenerator(item, getRealIndex(index))
    }
    return item.id || getRealIndex(index)
  }

  /**
   * 更新可视范围
   */
  const updateVisibleRange = () => {
    if (!enabled.value) {
      visibleRange.value = {
        start: 0,
        end: props.items.length - 1,
        paddingTop: 0,
        paddingBottom: 0
      }
      return
    }

    visibleRange.value = scroller.calculateVisibleRange(scrollTop.value)
  }

  /**
   * 滚动到指定索引
   */
  const scrollToIndex = (index: number) => {
    if (!containerRef.value) return

    const scrollTop = scroller.scrollToIndex(index)
    containerRef.value.scrollTop = scrollTop
  }

  /**
   * 更新容器高度
   */
  const updateContainerHeight = () => {
    if (containerRef.value) {
      containerHeight.value = containerRef.value.clientHeight
      scroller.updateContainerHeight(containerHeight.value)
    }
  }

  // 监听items变化
  watch(
    () => props.items,
    () => {
      scroller.updateItems(props.items)
      updateVisibleRange()
    },
    { immediate: true }
  )

  // 监听滚动位置变化
  watch(scrollTop, updateVisibleRange)

  // ResizeObserver
  let resizeObserver: ResizeObserver | null = null

  onMounted(() => {
    // 初始化虚拟滚动器
    scroller.init({
      itemHeight: props.itemHeight,
      bufferSize: props.bufferSize,
      threshold: props.threshold,
      containerHeight: containerHeight.value
    })

    // 更新容器高度
    updateContainerHeight()

    // 监听容器尺寸变化
    if (containerRef.value) {
      resizeObserver = new ResizeObserver(() => {
        updateContainerHeight()
        updateVisibleRange()
      })
      resizeObserver.observe(containerRef.value)
    }
  })

  onBeforeUnmount(() => {
    if (resizeObserver) {
      resizeObserver.disconnect()
      resizeObserver = null
    }
  })

  // 暴露方法
  defineExpose({
    scrollToIndex,
    updateContainerHeight
  })
</script>

<style scoped>
  .virtual-scroll-container {
    overflow: hidden auto;
    width: 100%;
    height: 100%;
  }

  .virtual-scroll-content {
    width: 100%;
  }

  .virtual-scroll-item {
    width: 100%;
    box-sizing: border-box;
  }
</style>
