/**
 * 输入速度追踪器
 * @module performance/debounce/input-tracker
 */

import { getConfig } from '../config'

/**
 * 输入速度追踪器
 * 记录输入事件时间戳,计算平均输入间隔
 */
export class InputTracker {
  /** 输入时间戳队列 */
  private timestamps: number[] = []
  /** 最大记录数量 */
  private maxRecords: number = 10

  /**
   * 记录输入事件
   */
  recordInput(): void {
    const now = Date.now()
    this.timestamps.push(now)

    // 保持队列长度不超过maxRecords
    if (this.timestamps.length > this.maxRecords) {
      this.timestamps.shift()
    }
  }

  /**
   * 获取平均输入间隔(ms)
   * @returns 平均间隔,如果记录不足2次返回0
   */
  getAverageInterval(): number {
    if (this.timestamps.length < 2) {
      return 0
    }

    let totalInterval = 0
    for (let i = 1; i < this.timestamps.length; i++) {
      totalInterval += this.timestamps[i] - this.timestamps[i - 1]
    }

    return totalInterval / (this.timestamps.length - 1)
  }

  /**
   * 获取推荐的防抖延迟时间
   * 根据输入速度动态调整
   * @returns 推荐延迟时间(ms)
   */
  getRecommendedDelay(): number {
    const config = getConfig()
    const avgInterval = this.getAverageInterval()

    // 如果没有足够的输入记录,使用最小延迟
    if (avgInterval === 0) {
      return config.debounce.minDelay
    }

    // 根据输入速度映射防抖时间
    // 输入越快(间隔越小),防抖时间越长
    if (avgInterval < 50) {
      // 非常快速的输入,使用最大延迟
      return config.debounce.maxDelay
    } else if (avgInterval < 100) {
      // 快速输入,使用中等延迟
      return Math.round(
        config.debounce.minDelay +
          (config.debounce.maxDelay - config.debounce.minDelay) * 0.7
      )
    } else if (avgInterval < 200) {
      // 正常输入,使用较小延迟
      return Math.round(
        config.debounce.minDelay +
          (config.debounce.maxDelay - config.debounce.minDelay) * 0.4
      )
    } else {
      // 慢速输入,使用最小延迟
      return config.debounce.minDelay
    }
  }

  /**
   * 清空记录
   */
  clear(): void {
    this.timestamps = []
  }

  /**
   * 获取记录数量
   */
  get recordCount(): number {
    return this.timestamps.length
  }
}

/**
 * 全局输入追踪器实例
 */
export const inputTracker = new InputTracker()
