/**
 * Worker通信封装
 * @module performance/worker/worker-communication
 */

import type { WorkerTask, WorkerMessage } from '../types'
import { getConfig } from '../config'

/**
 * Worker通信管理器
 * 封装Worker消息通信,提供Promise接口
 */
export class WorkerCommunication {
  private worker: Worker | null = null
  private pendingTasks: Map<string, {
    resolve: (value: any) => void
    reject: (error: Error) => void
    timeout: ReturnType<typeof setTimeout>
  }> = new Map()
  private taskIdCounter: number = 0

  /**
   * 设置Worker实例
   * @param worker Worker实例
   */
  setWorker(worker: Worker): void {
    this.worker = worker
    this.setupMessageHandler()
  }

  /**
   * 设置消息处理器
   */
  private setupMessageHandler(): void {
    if (!this.worker) return

    this.worker.onmessage = (event: MessageEvent<WorkerMessage>) => {
      const { id, result, error } = event.data

      // 忽略ready消息
      if (id === 'ready') return

      const pending = this.pendingTasks.get(id)
      if (!pending) return

      // 清除超时定时器
      clearTimeout(pending.timeout)
      this.pendingTasks.delete(id)

      // 处理结果或错误
      if (error) {
        pending.reject(new Error(error))
      } else {
        pending.resolve(result)
      }
    }

    this.worker.onerror = (error) => {
      console.error('Worker error:', error)
    }
  }

  /**
   * 发送任务并等待结果
   * @param task 任务
   * @returns Promise结果
   */
  postMessage<T = any, R = any>(task: Omit<WorkerTask<T>, 'id'>): Promise<R> {
    return new Promise((resolve, reject) => {
      if (!this.worker) {
        reject(new Error('Worker not initialized'))
        return
      }

      // 生成任务ID
      const id = `task-${++this.taskIdCounter}`
      const fullTask: WorkerTask<T> = { id, ...task }

      // 设置超时
      const config = getConfig()
      const timeout = setTimeout(() => {
        this.pendingTasks.delete(id)
        reject(new Error(`Task timeout: ${id}`))
      }, config.worker.timeout)

      // 保存pending任务
      this.pendingTasks.set(id, { resolve, reject, timeout })

      // 发送消息
      this.worker.postMessage(fullTask)
    })
  }

  /**
   * 清除所有待处理任务
   */
  clearPending(): void {
    this.pendingTasks.forEach((pending) => {
      clearTimeout(pending.timeout)
      pending.reject(new Error('Task cancelled'))
    })
    this.pendingTasks.clear()
  }

  /**
   * 获取待处理任务数量
   */
  getPendingCount(): number {
    return this.pendingTasks.size
  }
}
