/**
 * 性能优化配置
 * @module performance/config
 */

import type { PerformanceConfig } from './types'

/**
 * 默认性能配置
 */
export const defaultPerformanceConfig: PerformanceConfig = {
  // 防抖配置
  debounce: {
    minDelay: 100, // 最小防抖时间100ms
    maxDelay: 200, // 最大防抖时间200ms
    adaptive: true // 启用自适应防抖
  },

  // 虚拟滚动配置
  virtualScroll: {
    threshold: 50, // 超过50项启用虚拟滚动
    bufferSize: 5, // 缓冲区大小5项
    enabled: true // 启用虚拟滚动
  },

  // 缓存配置
  cache: {
    styleMaxSize: 20, // 样式缓存最大20项
    translationMaxSize: 100, // 翻译缓存最大100项
    autocompleteMaxSize: 50, // 自动补全缓存最大50项
    enabled: true // 启用缓存
  },

  // Worker配置
  worker: {
    timeout: 5000, // Worker超时时间5秒
    enabled: true // 启用Worker
  },

  // 批量更新配置
  batch: {
    enabled: true // 启用批量更新
  },

  // Watch配置
  watch: {
    shallow: true // 使用浅层watch
  }
}

/**
 * 当前性能配置
 */
let currentConfig = { ...defaultPerformanceConfig }

/**
 * 获取当前配置
 */
export function getConfig(): PerformanceConfig {
  return currentConfig
}

/**
 * 更新配置
 * @param partialConfig 部分配置
 */
export function updateConfig(partialConfig: Partial<PerformanceConfig>): void {
  currentConfig = mergeConfig(currentConfig, partialConfig)
}

/**
 * 重置为默认配置
 */
export function resetConfig(): void {
  currentConfig = { ...defaultPerformanceConfig }
}

/**
 * 合并配置
 * @param base 基础配置
 * @param partial 部分配置
 */
function mergeConfig(
  base: PerformanceConfig,
  partial: Partial<PerformanceConfig>
): PerformanceConfig {
  return {
    debounce: { ...base.debounce, ...partial.debounce },
    virtualScroll: { ...base.virtualScroll, ...partial.virtualScroll },
    cache: { ...base.cache, ...partial.cache },
    worker: { ...base.worker, ...partial.worker },
    batch: { ...base.batch, ...partial.batch },
    watch: { ...base.watch, ...partial.watch }
  }
}

/**
 * 性能优化开关配置
 * 用于独立控制各个优化模块
 */
export const optimizationToggles = {
  /** Watch优化开关 */
  get watchOptimization(): boolean {
    return currentConfig.watch.shallow
  },
  set watchOptimization(value: boolean) {
    currentConfig.watch.shallow = value
  },

  /** 动态防抖开关 */
  get dynamicDebounce(): boolean {
    return currentConfig.debounce.adaptive
  },
  set dynamicDebounce(value: boolean) {
    currentConfig.debounce.adaptive = value
  },

  /** 虚拟滚动开关 */
  get virtualScroll(): boolean {
    return currentConfig.virtualScroll.enabled
  },
  set virtualScroll(value: boolean) {
    currentConfig.virtualScroll.enabled = value
  },

  /** 缓存开关 */
  get cache(): boolean {
    return currentConfig.cache.enabled
  },
  set cache(value: boolean) {
    currentConfig.cache.enabled = value
  },

  /** Worker开关 */
  get worker(): boolean {
    return currentConfig.worker.enabled
  },
  set worker(value: boolean) {
    currentConfig.worker.enabled = value
  },

  /** 批量更新开关 */
  get batch(): boolean {
    return currentConfig.batch.enabled
  },
  set batch(value: boolean) {
    currentConfig.batch.enabled = value
  }
}
