/**
 * 批量更新器
 * @module performance/batch/batch-updater
 */

import { nextTick } from 'vue'
import type { BatchUpdater, UpdateTask, StorageItem, StateUpdate } from '../types'
import { getConfig } from '../config'

/**
 * 批量更新器实现
 * 使用requestAnimationFrame批量执行更新任务,减少重渲染次数
 */
export class BatchUpdaterImpl implements BatchUpdater {
  /** 任务队列 */
  private taskQueue: Map<string, UpdateTask> = new Map()
  /** 是否已调度 */
  private scheduled: boolean = false
  /** 执行次数统计 */
  private executeCount: number = 0

  /**
   * 添加任务到队列
   * 相同ID的任务会被去重,只保留最新的
   * @param task 更新任务
   */
  queue(task: UpdateTask): void {
    // 去重:相同ID只保留最新任务
    this.taskQueue.set(task.id, task)

    // 调度执行
    this.scheduleFlush()
  }

  /**
   * 调度批量执行
   */
  private scheduleFlush(): void {
    const config = getConfig()

    // 检查是否启用批量更新
    if (!config.batch.enabled) {
      // 未启用则立即执行
      this.flush()
      return
    }

    // 如果已调度则跳过
    if (this.scheduled) return

    // 使用requestAnimationFrame调度
    this.scheduled = true
    requestAnimationFrame(() => {
      this.flush()
      this.scheduled = false
    })
  }

  /**
   * 清空队列
   */
  clear(): void {
    this.taskQueue.clear()
  }

  /**
   * 立即执行所有任务
   */
  flush(): void {
    if (this.taskQueue.size === 0) return

    // 按优先级排序(可选)
    const tasks = Array.from(this.taskQueue.values())
      .sort((a, b) => (b.priority ?? 0) - (a.priority ?? 0))

    // 清空队列
    this.taskQueue.clear()

    // 执行所有任务
    try {
      tasks.forEach((task) => {
        task.fn()
      })
      this.executeCount++
    } catch (error) {
      console.error('Batch update error:', error)
    }
  }

  /**
   * 批量更新localStorage
   * @param items 存储项数组
   */
  batchLocalStorage(items: StorageItem[]): void {
    const config = getConfig()

    if (!config.batch.enabled) {
      // 未启用批量更新,直接执行
      items.forEach((item) => {
        localStorage.setItem(item.key, item.value)
      })
      return
    }

    // 添加到队列
    items.forEach((item) => {
      this.queue({
        id: `localStorage-${item.key}`,
        fn: () => {
          localStorage.setItem(item.key, item.value)
        },
        priority: 0
      })
    })
  }

  /**
   * 批量更新Vue状态
   * @param updates 状态更新数组
   */
  async batchVueState(updates: StateUpdate[]): Promise<void> {
    const config = getConfig()

    if (!config.batch.enabled) {
      // 未启用批量更新,直接执行
      updates.forEach((update) => {
        update.target[update.prop] = update.value
      })
      return
    }

    // 使用nextTick确保在一次渲染周期内完成
    await nextTick()

    // 批量更新
    updates.forEach((update) => {
      update.target[update.prop] = update.value
    })
  }

  /**
   * 获取队列大小
   */
  getQueueSize(): number {
    return this.taskQueue.size
  }

  /**
   * 获取执行次数
   */
  getExecuteCount(): number {
    return this.executeCount
  }

  /**
   * 是否有待执行任务
   */
  hasPending(): boolean {
    return this.taskQueue.size > 0
  }
}

/**
 * 全局批量更新器实例
 */
export const batchUpdater = new BatchUpdaterImpl()
