/**
 * LRU缓存实现
 * @module performance/cache/lru-cache
 */

import type { LRUCache, CacheStats } from '../types'

/**
 * LRU缓存类
 * 使用Map数据结构实现最近最少使用缓存淘汰策略
 */
export class LRUCacheImpl<K = string, V = any> implements LRUCache<K, V> {
  private cache: Map<K, V>
  private maxSize: number
  private hits: number = 0
  private misses: number = 0

  /**
   * 构造函数
   * @param maxSize 最大缓存容量,默认100
   */
  constructor(maxSize: number = 100) {
    this.maxSize = maxSize
    this.cache = new Map()
  }

  /**
   * 获取缓存值
   * 如果存在则更新使用顺序(删除后重新添加)
   * @param key 缓存键
   * @returns 缓存值或undefined
   */
  get(key: K): V | undefined {
    if (this.cache.has(key)) {
      // 命中,更新使用顺序
      const value = this.cache.get(key)!
      this.cache.delete(key)
      this.cache.set(key, value)
      this.hits++
      return value
    }
    // 未命中
    this.misses++
    return undefined
  }

  /**
   * 设置缓存值
   * 如果超出容量则淘汰最久未使用的项
   * @param key 缓存键
   * @param value 缓存值
   */
  set(key: K, value: V): void {
    // 如果已存在,先删除
    if (this.cache.has(key)) {
      this.cache.delete(key)
    }
    // 如果超出容量,删除最久未使用的项(Map的第一个元素)
    else if (this.cache.size >= this.maxSize) {
      const firstKey = this.cache.keys().next().value
      this.cache.delete(firstKey)
    }
    // 添加新项
    this.cache.set(key, value)
  }

  /**
   * 检查缓存是否存在
   * @param key 缓存键
   * @returns 是否存在
   */
  has(key: K): boolean {
    return this.cache.has(key)
  }

  /**
   * 删除缓存项
   * @param key 缓存键
   * @returns 是否删除成功
   */
  delete(key: K): boolean {
    return this.cache.delete(key)
  }

  /**
   * 清空所有缓存
   */
  clear(): void {
    this.cache.clear()
    this.hits = 0
    this.misses = 0
  }

  /**
   * 获取缓存统计信息
   * @returns 缓存统计
   */
  getStats(): CacheStats {
    const total = this.hits + this.misses
    const hitRate = total > 0 ? this.hits / total : 0

    return {
      size: this.cache.size,
      maxSize: this.maxSize,
      hits: this.hits,
      misses: this.misses,
      hitRate
    }
  }

  /**
   * 获取当前缓存大小
   */
  get size(): number {
    return this.cache.size
  }
}
